import sys
sys.path.insert(0, "../connections") 

import connection_snowflake
import generate_random_user

from snowflake.snowpark import Window
from snowflake.snowpark.functions import row_number

#Snowflake Snowpark connection
session = connection_snowflake.new_session

#Create dummy_user_data table, if not exists
session.sql('CREATE OR REPLACE TABLE dummy_user_data ("user_id" INTEGER, "first_name" VARCHAR(30), "last_name" VARCHAR(30), "email" VARCHAR(50))').collect()

#Get users data, generated by using randomuser API
#An single API call has maximum of 5000 returned users
#Convert to dataframe & insert into dummy_user_data
persons_data = generate_random_user.generate_random_name_and_surname(5000)
df = session.create_dataframe(persons_data, schema=["first_name", "last_name", "email"])

# Create global row number
window_spec = Window.order_by("email")
df_with_id = df.with_column("user_id", row_number().over(window_spec))

# Reorder columns to match table
df_with_id = df_with_id.select("user_id", "first_name", "last_name", "email")

# Insert into table
df_with_id.write.mode("append").save_as_table("dummy_user_data")

#Close opened session
session.close()